import{_ as a,o as e,c as n,a2 as o}from"./chunks/framework.Bix3-HpO.js";const c=JSON.parse('{"title":"Translating FXT Theme","description":"Translating FXT Theme","frontmatter":{"title":"Translating FXT Theme","description":"Translating FXT Theme","weight":150,"extra":{"order":150},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/translation"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/translation"}],["meta",{"property":"og:title","content":"Translating FXT Theme"}],["meta",{"property":"og:description","content":"Translating FXT Theme"}],["meta",{"name":"twitter:title","content":"Translating FXT Theme"}],["meta",{"name":"twitter:description","content":"Translating FXT Theme"}]]},"headers":[],"relativePath":"docs/fxt/translation.md","filePath":"docs/fxt/translation.md"}'),r={name:"docs/fxt/translation.md"};function l(i,t,s,d,g,h){return e(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="translating-fxt" tabindex="-1">Translating FXT <a class="header-anchor" href="#translating-fxt" aria-label="Permalink to &quot;Translating FXT&quot;">​</a></h1><p>FXT is ready to be translated into any language and can be used on multilingual websites.</p><h2 id="single-language" tabindex="-1">Single Language <a class="header-anchor" href="#single-language" aria-label="Permalink to &quot;Single Language&quot;">​</a></h2><p>If your site has a single language, you don&#39;t need a multilingual plugin. FXT&#39;s user‑facing text can be translated using standard translation tools such as <a href="https://localise.biz/wordpress/plugin" target="_blank" rel="noreferrer">Loco Translate</a>.</p><h3 id="loco-translate" tabindex="-1">Loco Translate <a class="header-anchor" href="#loco-translate" aria-label="Permalink to &quot;Loco Translate&quot;">​</a></h3><ul><li>Translate the theme directly in your dashboard. You&#39;ll see two text domains: <ul><li><code>fxt</code> - frontend strings</li><li><code>fxt-admin</code> - dashboard/editor strings (you don&#39;t need to translate these)</li></ul></li><li>Save translations to &quot;System&quot; so they persist after updates.</li></ul><h3 id="fxt-strings" tabindex="-1">FXT Strings <a class="header-anchor" href="#fxt-strings" aria-label="Permalink to &quot;FXT Strings&quot;">​</a></h3><p>FXT also includes a Strings page in the admin (<a href="/docs/fxt/theme-strings">FXT Options → 💬 Strings</a>) where you can override specific labels without a translator plugin. This is handy when you only need to tweak user-facing texts.</p><h2 id="multilingual" tabindex="-1">Multilingual <a class="header-anchor" href="#multilingual" aria-label="Permalink to &quot;Multilingual&quot;">​</a></h2><p>FXT supports popular multilingual plugins. Below are short guides on the 2 most popular ones.</p><h3 id="wpml" tabindex="-1">WPML <a class="header-anchor" href="#wpml" aria-label="Permalink to &quot;WPML&quot;">​</a></h3><p><a href="https://wpml.org" target="_blank" rel="noreferrer">WPML</a> is a comprehensive multilingual solution. Before getting started you may want to check out their <a href="https://wpml.org/documentation/getting-started-guide/" target="_blank" rel="noreferrer">Getting Started guide</a>.</p><ol><li>Install and activate &quot;WPML Multilingual CMS&quot; and &quot;WPML String Translation&quot;.</li><li>Run the WPML setup wizard (languages, defaults, etc.).</li><li>Scan theme strings: WPML → Theme and plugins localization → Scan the &quot;FXT&quot; theme.</li><li>Translate content (pages, posts, brokers) using the &quot;+&quot; in the editor lists.</li><li>Translate theme strings: WPML → String Translation → filter by domain <code>fxt</code> (frontend) and <code>fxt-admin</code> (dashboard).</li></ol><p>FXT provides context strings to help you find groups quickly (e.g., &quot;fxt‑string: ...&quot;, &quot;list: platform/country/...&quot;).</p><h3 id="polylang-with-loco-translate" tabindex="-1">Polylang (with Loco Translate) <a class="header-anchor" href="#polylang-with-loco-translate" aria-label="Permalink to &quot;Polylang (with Loco Translate)&quot;">​</a></h3><p><a href="https://polylang.pro" target="_blank" rel="noreferrer">Polylang</a> is a lightweight multilingual plugin. CHeck their Getting Started](<a href="https://polylang.pro/doc-category/getting-started/" target="_blank" rel="noreferrer">https://polylang.pro/doc-category/getting-started/</a>) for more information.</p><ul><li>Polylang Free version doesn&#39;t list theme strings automatically in &quot;Strings translations&quot;; pair it with Loco Translate for theme strings.</li><li>Polylang Pro may be another option for translating theme strings.</li></ul><p>Getting started:</p><ol><li>Install and activate Polylang. Add your languages.</li><li>Translate content (pages, posts, brokers) using the &quot;+&quot; in the editor lists.</li><li>Translate theme strings with Loco Translate: <ul><li>Loco → Themes → FXT → Templates</li><li>Create a language for <code>fxt</code> (frontend) and for <code>fxt-admin</code> (dashboard)</li><li>Translate only the strings you need</li></ul></li></ol><h3 id="rtl-and-ttb" tabindex="-1">RTL and TTB <a class="header-anchor" href="#rtl-and-ttb" aria-label="Permalink to &quot;RTL and TTB&quot;">​</a></h3><p>FXT supports both right‑to‑left (RTL) and top‑to‑bottom (TTB) languages.</p><hr><h3 id="need-help" tabindex="-1">Need help? <a class="header-anchor" href="#need-help" aria-label="Permalink to &quot;Need help?&quot;">​</a></h3><ul><li>WPML: see their <a href="https://wpml.org/documentation/getting-started-guide/" target="_blank" rel="noreferrer">Getting Started guide</a> and String Translation docs.</li><li>Polylang: see the <a href="https://polylang.pro/doc-category/getting-started/" target="_blank" rel="noreferrer">Getting Started</a> docs.</li><li>Loco Translate: simple in‑dashboard translation editor - no FTP required.</li></ul><p>Translate what matters first (frontend <code>fxt</code>), and come back to <code>fxt-admin</code> for dashboard texts when ready.</p>',25)])])}const p=a(r,[["render",l]]);export{c as __pageData,p as default};
